<script setup lang="ts">
import { computed, watch } from 'vue';import { useRoute,useRouter } from 'vue-router';import { useMerchantContext } from '../stores/merchantContext'
const route=useRoute();const router=useRouter();const ctx=useMerchantContext();const current=computed(()=>ctx.merchant.value);const tabs=[['overview','总览'],['facts','商家事实'],['platform-assets','平台资产'],['questions-observations','AI观察'],['observation-automation','自动观察与证据'],['diagnosis-strategy','诊断与策略'],['execution','执行中心'],['retests-reports','复测与报告'],['playbooks','策略库']];const tabMeta:any={overview:['聚合当前商家诊断与执行状态','检查待办后进入对应步骤'],facts:['维护可验证的商家事实来源','补齐缺失事实，再开始观察'], 'platform-assets':['归档各平台官方资料与链接','该能力尚待后续接入'], 'questions-observations':['人工记录消费者问题与各平台AI回答','录入观察后查看可见度指标和整改任务'], 'observation-automation':['通过授权 API 采集并核验观察、信源和作品引用','先配置官方 API，再人工确认 DRAFT 观察'], 'diagnosis-strategy':['生成正式评分并定位Gap','确认策略后进入任务执行'],execution:['生成、审核、登记内容发布','发布后维护收录状态'], 'retests-reports':['跟踪14天与30天复测节点','按计划导入复测证据'],playbooks:['沉淀可复用的行业策略','该能力尚待后续接入']}
watch(()=>route.params.merchantId,id=>ctx.load(String(id)),{immediate:true});const active=computed(()=>String(route.name||route.path).split('/').pop()||'overview');const selectedMerchantId=computed({get:()=>current.value?.id||'',set:(id:string)=>id&&router.push(`/merchants/${id}/overview`)});const meta=computed(()=>tabMeta[active.value]||tabMeta.overview);function go(path:string){router.push(`/merchants/${ctx.merchant.value?.id}/${path}`)}
</script>
<template><div class="workspace-shell"><aside class="workspace-sidebar"><div class="workspace-brand">LAIG<span> · 商家增长</span></div><div v-if="current" class="workspace-merchant"><b>{{current.name}}</b><small>{{current.city}} · {{current.industry}}</small></div><nav><button v-for="tab in tabs" :key="tab[0]" :class="{active:active===tab[0]}" @click="go(tab[0])">{{tab[1]}}</button></nav></aside><main class="workspace-main"><header class="workspace-topbar"><div><span class="eyebrow">LOCAL AI GROWTH OS</span><h1>{{current?.name||'商家工作台'}}</h1></div><div class="topbar-actions"><el-select v-if="ctx.merchants.value.length>1" v-model="selectedMerchantId" aria-label="切换商家"><el-option v-for="merchant in ctx.merchants.value" :key="merchant.id" :value="merchant.id" :label="merchant.name"/></el-select><el-tag v-if="ctx.data.provider" :type="ctx.data.provider.configured?'success':'warning'">DeepSeek {{ctx.data.provider.configured?'可用':'未配置'}}</el-tag></div></header><div class="workspace-module-status"><span>模块作用：{{meta[0]}}</span><b>下一步：{{meta[1]}}</b></div><router-view/></main></div></template>
